-- Import NetUp users from:
-- 1. add_user.txt
-- 2. ĐĂNG KÝ THAM GIA GIẢI ĐẤU NETUP MASTER CHAMPIONSHIP 2026 (Câu trả lời) - Câu trả lời biểu mẫu 1.csv
--
-- Generated by Codex on 2026-06-30.
-- Raw student rows: 123; unique student users: 106.
-- Raw CSV participant rows: 66; unique CSV participant rows: 65.
-- CSV participants matched to student users: 2; CSV-only users added: 63.
-- Total unique users in this import: 169.
--
-- This SQL is idempotent: running it again updates existing users by email,
-- keeps existing phone when present, and does not duplicate player roles or Elo rows.

BEGIN;

CREATE TEMP TABLE tmp_netup_user_import (
  email text PRIMARY KEY,
  full_name text NOT NULL,
  phone text,
  source text NOT NULL,
  student_code text
) ON COMMIT DROP;

ON CONFLICT (email) DO UPDATE SET
  full_name = EXCLUDED.full_name,
  phone = COALESCE(tmp_netup_user_import.phone, EXCLUDED.phone),
  source = tmp_netup_user_import.source || ' + ' || EXCLUDED.source,
  student_code = COALESCE(NULLIF(tmp_netup_user_import.student_code, ''), EXCLUDED.student_code);

-- Upsert user profiles.
SELECT
  email::citext,
  full_name,
  NULLIF(phone, ''),
  true
FROM tmp_netup_user_import
ON CONFLICT (email) DO UPDATE SET
  full_name = EXCLUDED.full_name,
  phone = COALESCE(NULLIF(public.users.phone, ''), EXCLUDED.phone),
  is_active = true,
  updated_at = now();

-- Grant player role for imported users.
SELECT u.id, 'player'::public.user_role, 'bulk import: add_user + tournament csv'
FROM public.users u
JOIN tmp_netup_user_import i ON i.email::citext = u.email
ON CONFLICT DO NOTHING;

-- Create default Elo profile so rating-dependent screens have a row ready.
  player_user_id,
  elo_value,
  visible_skill_tier,
  matches_played,
  wins,
  losses,
  draws
)
SELECT
  u.id,
  1000,
  'Beginner'::public.skill_tier,
  0,
  0,
  0,
  0
FROM public.users u
JOIN tmp_netup_user_import i ON i.email::citext = u.email
ON CONFLICT (player_user_id) DO NOTHING;

-- Quick verification result after import.
SELECT
  count(*) AS imported_user_count,
  count(*) FILTER (WHERE i.source LIKE '%add_user%') AS from_add_user_or_matched,
  count(*) FILTER (WHERE i.source LIKE '%tournament_csv%') AS from_tournament_csv_or_matched,
  count(*) FILTER (WHERE u.phone IS NOT NULL) AS users_with_phone
FROM tmp_netup_user_import i
JOIN public.users u ON u.email = i.email::citext;

COMMIT;
